{
  "title": "Primary Biology Exam",
   "description": "A 60-minute exam to assess primary students' understanding of basic biology concepts",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice questions",
           "questions": [
               {
                   "text": "What is the main function of the roots of a plant?",
                   "type": "multiple-choice",
                   "points": 10,
                   "difficulty": "easy",
                   "options": [
                       {"text": "To make food for the plant", "isCorrect": false, "letter": "A"},
                       {"text": "To hold the plant upright", "isCorrect": false, "letter": "B"},
                       {"text": "To absorb water and nutrients from the soil", "isCorrect": true, "letter": "C"},
                       {"text": "To produce flowers and seeds", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "C"
               },
               {
                   "text": "Which part of the human body helps us to breathe?",
                   "type": "multiple-choice",
                   "points": 10,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Heart", "isCorrect": false, "letter": "A"},
                       {"text": "Lungs", "isCorrect": true, "letter": "B"},
                       {"text": "Brain", "isCorrect": false, "letter": "C"},
                       {"text": "Liver", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               },
               {
                   "text": "What is the process called when plants make their own food from sunlight?",
                   "type": "multiple-choice",
                   "points": 15,
                   "difficulty": "medium",
                   "options": [
                       {"text": "Respiration", "isCorrect": false, "letter": "A"},
                       {"text": "Photosynthesis", "isCorrect": true, "letter": "B"},
                       {"text": "Decomposition", "isCorrect": false, "letter": "C"},
                       {"text": "Fermentation", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               },
               {
                   "text": "Which sense organ helps us to see?",
                   "type": "multiple-choice",
                   "points": 10,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Ears", "isCorrect": false, "letter": "A"},
                       {"text": "Eyes", "isCorrect": true, "letter": "B"},
                       {"text": "Nose", "isCorrect": false, "letter": "C"},
                       {"text": "Tongue", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               },
               {
                   "text": "What is the main function of the skeleton in the human body?",
                   "type": "multiple-choice",
                   "points": 15,
                   "difficulty": "medium",
                   "options": [
                       {"text": "To produce blood cells", "isCorrect": false, "letter": "A"},
                       {"text": "To protect internal organs", "isCorrect": true, "letter": "B"},
                       {"text": "To help us move", "isCorrect": false, "letter": "C"},
                       {"text": "To regulate body temperature", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended questions",
           "questions": [
               {
                   "text": "Describe the basic needs of plants for survival.",
                   "type": "open-ended",
                   "points": 20,
                   "difficulty": "medium",
                   "correctAnswer": "Plants need water, sunlight, air, and soil to survive. Water is necessary for photosynthesis and transportation of nutrients, sunlight provides energy for photosynthesis, air provides carbon dioxide for photosynthesis, and soil provides nutrients and support for the plant's roots."
               },
               {
                   "text": "Explain the importance of conservation of natural habitats and ecosystems.",
                   "type": "open-ended",
                   "points": 30,
                   "difficulty": "hard",
                   "correctAnswer": "Conservation of natural habitats and ecosystems is important because it helps to preserve biodiversity, maintain ecosystem services such as clean air and water, and protect endangered species. It also helps to mitigate the effects of climate change, supports human health and well-being, and provides opportunities for recreation and tourism."
               }
           ]
       }
   ]
}
